import java.io.*;import java.util.*;
class Main{static boolean pal(String s){for(int i=0,j=s.length()-1;i<j;i++,j--)if(s.charAt(i)!=s.charAt(j))return false;return true;}static String rev(String s){return new StringBuilder(s).reverse().toString();}static List<int[]> solve(String[] w){Map<String,Integer> pos=new HashMap<>();for(int i=0;i<w.length;i++)pos.put(w[i],i);List<int[]> ans=new ArrayList<>();for(int i=0;i<w.length;i++){for(int c=0;c<=w[i].length();c++){String pre=w[i].substring(0,c),suf=w[i].substring(c);if(pal(pre)){Integer j=pos.get(rev(suf));if(j!=null&&j!=i)ans.add(new int[]{j,i});}if(c<w[i].length()&&pal(suf)){Integer j=pos.get(rev(pre));if(j!=null&&j!=i)ans.add(new int[]{i,j});}}}ans.sort((a,b)->a[0]==b[0]?a[1]-b[1]:a[0]-b[0]);return ans;}static String fmt(List<int[]> p){StringBuilder sb=new StringBuilder("[");for(int i=0;i<p.size();i++){if(i>0)sb.append(',');sb.append('[').append(p.get(i)[0]).append(',').append(p.get(i)[1]).append(']');}return sb.append(']').toString();}public static void main(String[]a)throws Exception{String[] d=new String(System.in.readAllBytes()).trim().split("\\s+");if(d.length==1&&d[0].isEmpty())return;int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);String[] w=new String[n];for(int i=0;i<n;i++){w[i]=d[idx++];if(w[i].equals("_"))w[i]="";}if(tc>0)out.append("\n\n");out.append(fmt(solve(w)));}System.out.print(out);}}
